dir.commands:
    &XMLWhenFilterLoading;
    &XMLWhenFilterClosing;




declare @k varchar(256)
select @k = rtrim(case when b.dvcs_yn = 0 then '0' else a.dvcs end) + ',' + (case when b.bp_yn = 0 then '0' else a.ma_bp end) + ',' + (case when b.hrbp_yn = 0 then '0' else a.ma_hrbp end) + ',' + (case when b.kh_yn = 0 then '0' else a.nh_kh1 end) + ',' + (case when b.kh_yn = 0 then '0' else a.nh_kh2 end) + ',' + (case when b.kh_yn = 0 then '0' else a.nh_kh3 end) + ',' + (case when b.tk_yn = 0 then '0' else a.tk end) + ',' + (case when b.sl_yn = 0 then '0' else a.so_luong end) + ',' + (case when b.tien_yn = 0 then '0' else a.tien end) + ',' + (case when b.tien_yn = 0 then '0' else a.ma_nt end) + ',' + (case when b.loai_ct_yn = 0 then '0' else a.loai_ct end) from gndmkieuduyet a left join gndmloaiduyet b on a.loai_duyet = b.loai_duyet where a.loai_duyet = @loai_duyet and ma_kieu = @ma_kieu
select '' as field, '' as message, 'set$VoucherFilter$(this, [' + rtrim(@k) + ']);' as script
return

script.text:
      &JavascriptReportFilter;
      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  f.setReferenceKeyFilter('ma_kieu');
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(f, e) {
  var f = e.object, g = f.grid, context = e.type.Context;
  switch (context) {
    case 'Checking':
      var g = f.grid, v = f._language == 'v', k = new Array();
      g._approvalType = f.getItemValue('loai_duyet');
      g._approvalCategory = f.getItemValue('ma_kieu');
      g._approvalCategoryName = f.getItemValue('ten_kieu%l');
      g._approvalName = f.getItemValue('ten_loai_duyet');
      Array.add(k, {Name: 'loai_duyet', Opr: '=', Value: g._approvalType, Type: 'String', Ignore: false});
      Array.add(k, {Name: 'ma_kieu', Opr: '=', Value: f.getItemValue('ma_kieu'), Type: 'String', Ignore: false});
      g.set_externalKey(k);
      g._alterTitle = [null, [['%c', g._approvalType + ' - ' + g._approvalName, true], ['%m', f.getItemValue('ma_kieu') + ' - ' + f.getItemValue('ten_kieu%l'), true]]];
      break;
    default:
      break;
  }
}
function onChange$Filter$GNApprovalCategoryDetail$Function(o) {o.parentForm.setReferenceKeyFilter('ma_kieu');}
function set$VoucherFilter$(sender, k) {
  var g = sender.grid;
  g._field_yn = [['dvcs', 'dvcs, ten_dvcs%l', 'dvcs'], ['ma_bp', 'ma_bp, ten_bp%l', 'ma_bp'], ['ma_hrbp', 'ma_hrbp, ten_hrbp%l', 'ma_hrbp'], ['nh_kh1', 'nh_kh1, ten_nh1%l', 'nh_kh1'], ['nh_kh2', 'nh_kh2, ten_nh2%l', 'nh_kh2'], ['nh_kh3', 'nh_kh3, ten_nh3%l', 'nh_kh3'], ['tk', 'tk, ten_tk%l', 'tk'], ['so_luong', 'sl_tu, sl_den', ''], ['tien', 'tien_tu, tien_den', ''], ['ma_nt', 'ma_nt', 'ma_nt'], ['loai_ct', 'loai_ct, ten_loai_ct%l', 'loai_ct']];
  for (var i = 0; i < g._field_yn.length; i++) {
    g._field_yn[i][0] = k[i] == '0';
  }
  g._hiddenFields = [];
  for (var i = 0; i < g._field_yn.length; i++) {
    Array.add(g._hiddenFields, {Fields: g._field_yn[i][1], Value: g._field_yn[i][0]});
  }
  remove$GridReport$Filter(g);
}
/* </flatten> */
